import React from "react";

function CreateDeck() {
  return (
    <div>
      <h1>Create Deck</h1>
      <h4 className="m-1">Name</h4>
      <form>
          <label>Name</label>
          <input type="text"></input>
          <label>Description</label>
          <textarea></textarea>
      </form>
    </div>
  );
}

export default CreateDeck;
